import java.util.*;
public class UnionContext extends org.apache.commons.jxpath.ri.axes.UnionContext implements Iterator {
    Vector pointersList;

    public UnionContext(){
       pointersList = new Vector(); 
    }
    @Override
    public boolean setPosition(int position) {
        if (!prepared) {
            prepared = true;
            org.apache.commons.jxpath.nodeset.BasicNodeSet nodeSet = (org.apache.commons.jxpath.nodeset.BasicNodeSet) getNodeSet();

            for (int i = 0; i < contexts.length; i++) {
                EvalContext ctx = (EvalContext) contexts[i];

                while (ctx.nextSet()) {

                    while (ctx.nextNode()) {

                        Object ptr = ctx.getCurrentNodePointer().getObject();

                        if (!pointersList.contains(ptr)) {

                            nodeSet.add((Node) ptr);

                            pointersList.add(ptr);
                        }
                    }
                }
            }

            Collections.sort(pointersList, new Comparator() {
               public int compare(Object o1, Object o2) {
                  int index1 = ((DocumentNavigator)o1).getCursor(),
                      index2 = ((DocumentNavigator)o2).getCursor();

                   return Integer.compare(index1,index2);
                }
            });

            Iterator itr = this.iterator(); 

            while (itr.hasNext()) {

                DocumentNavigator dn = (DocumentNavigator) itr.next();

                dn.setPosition(pointersList.indexOf(dn.getCurrentNodePointer().getObject()));
            }


        }



        return super.setPosition(position);
    }

}

